    const interval = setInterval(() => {
      current--;
      if (current <= 0) {
        clearInterval(interval);
        generateRecipesBtn.disabled = false;
        generateRecipesBtn.innerHTML = originalText;
      } else {
        generateRecipesBtn.innerHTML = `<i data-lucide="clock"></i> Cooldown: Wait ${current}s`;
        lucide.createIcons();
      }
    }, 1000);
    generateRecipesBtn.innerHTML = `<i data-lucide="clock"></i> Cooldown: Wait ${current}s`;
    lucide.createIcons();
